class Solution {
    public boolean digitCount(String num) {
        int n = num.length();
        for (int i = 0; i < n; i++) {
            int required = num.charAt(i) - '0';
            int actual = 0;
            for (int j = 0; j < n; j++) {
                if (num.charAt(j) == (char) (i + '0')) {
                    actual++;
                }
            }
            if (actual != required) {
                return false;
            }
        }
        return true;
    }
}

